pure fn char_frequency(s: Text) -> [Text] {
    freq = []
    for c in s {
        found = false
        for pair in freq {
            if get(pair, 0) == c {
                pair[1] = get(pair, 1) + 1
                found = true
                break
            }
        }
        if not found {
            append(freq, [c, 1])
        }
    }
    return freq
}
