pure fn days_between(date1: [Number], date2: [Number]) -> Number {
    year1 = get(date1, 0)
    month1 = get(date1, 1)
    day1 = get(date1, 2)
    year2 = get(date2, 0)
    month2 = get(date2, 1)
    day2 = get(date2, 2)
    days1 = year1 * 365 + month1 * 30 + day1
    days2 = year2 * 365 + month2 * 30 + day2
