pure fn fibonacci(n: Number) -> [Number] {
    if n <= 0 { return [] }
    if n == 1 { return [0] }
    if n == 2 { return [0, 1] }
    seq = [0, 1]
    for i in range(2, n) {
        next_value = get(seq, i-1) + get(seq, i-2)
        seq = append(seq, next_value)
    }
    return seq
}
intent explain_golden_ratio() -> Text {
